import { PublicActionPage } from '@domain/publicActionPage';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import { useMemo } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { Button } from 'src/builder/PublicActionPage/components/Button';
import {
  ApplePayLogoIcon,
  CloseIcon,
  GooglePayLogoIcon,
  LockIcon,
  PayPalLogoIcon,
} from 'src/builder/PublicActionPage/components/icons';
import { Label } from 'src/builder/PublicActionPage/components/Label';
import { Link } from 'src/builder/PublicActionPage/components/Link';
import { Meta } from 'src/builder/PublicActionPage/components/Meta';
import { useDisclosure } from 'src/builder/PublicActionPage/components/Modal';

type Props = {
  actionPage: PublicActionPage;
  isEmbedded?: boolean;
};

export const SecureNotice = ({ actionPage, isEmbedded }: Props) => {
  const { t } = useTranslation('common');

  const { isOpen, onClose, onOpen } = useDisclosure();

  const href = useMemo(() => {
    const params = new URLSearchParams(window.location.search);
    params.delete('embed');
    return window.location.href.replace(window.location.search, `?${params.toString()}`);
  }, []);

  const { pageType } = actionPage;
  const isDonation = isDonationPage(pageType);
  const { applepayEnabled, googlepayEnabled, paypalEnabled } =
    actionPage.paymentConfiguration || {};

  return (
    <div className="m-2 flex max-w-[346px] flex-col gap-6">
      {!isOpen ? (
        <Button
          className="flex min-h-[75px] cursor-pointer items-center justify-center gap-2"
          onClick={onOpen}
          variant="unstyled"
        >
          <LockIcon className="w-[16px] !text-neutral-600" />
          <Label className="!text-neutral-600" variant="medium">
            {t('form.secure')}
          </Label>
        </Button>
      ) : null}
      {isOpen ? (
        <div className="relative flex min-h-[75px] animate-fade-in flex-col gap-0 p-0 text-center">
          <Button
            className="absolute -right-[24px] top-[4px] w-[16px] cursor-pointer"
            onClick={onClose}
            variant="unstyled"
          >
            <CloseIcon />
          </Button>

          <Meta variant="regular">
            <Trans
              components={[
                <Link
                  className="!ml-0 !text-[13px]"
                  href="https://anedot.com"
                  isExternal
                  key="anedot-link"
                />,
              ]}
              i18nKey="secureNotice.anedotProtects"
              t={t}
            />
          </Meta>
          <Meta className="text-center" variant="regular">
            {t('secureNotice.questions')}
          </Meta>
        </div>
      ) : null}
      {isEmbedded && isDonation ? (
        <div className="flex justify-center">
          <div className="flex flex-col gap-1 rounded-md border border-neutral-700 p-2">
            {(applepayEnabled || googlepayEnabled || paypalEnabled) && (
              <div className="flex content-center justify-center gap-2">
                {applepayEnabled && <ApplePayLogoIcon className="text-black w-[30px]" />}
                {googlepayEnabled && <GooglePayLogoIcon className="w-[32px]" />}
                {paypalEnabled && <PayPalLogoIcon className="w-[39px]" />}
              </div>
            )}
            <Link className="text-center" href={href} isExternal>
              {t('secureNotice.availableOnHostedForm')}
            </Link>
          </div>
        </div>
      ) : null}
    </div>
  );
};

